 1→const MINUTE = 60_000;
 2→const HOUR = 3_600_000;
 3→const DAY = 86_400_000;
 4→
 5→export function formatRelativeDate(date: Date, now: Date = new Date()): string {
 6→  const diff = now.getTime() - date.getTime();
 7→
 8→  if (diff < 0) {
 9→    return formatAbsoluteDate(date, now);
10→  }
11→
12→  if (diff < MINUTE) {
13→    return 'Just now';
14→  }
15→
16→  if (diff < HOUR) {
17→    const minutes = Math.floor(diff / MINUTE);
18→    return `${minutes} ${minutes === 1 ? 'minute' : 'minutes'} ago`;
19→  }
20→
21→  if (diff < DAY) {
22→    const hours = Math.floor(diff / HOUR);
23→    return `${hours} ${hours === 1 ? 'hour' : 'hours'} ago`;
24→  }
25→
26→  if (diff < DAY * 2) {
27→    return 'Yesterday';
28→  }
29→
30→  if (diff < DAY * 7) {
31→    const days = Math.floor(diff / DAY);
32→    return `${days} days ago`;
33→  }
34→
35→  return formatAbsoluteDate(date, now);
36→}
37→
38→function formatAbsoluteDate(date: Date, now: Date): string {
39→  const sameYear = date.getFullYear() === now.getFullYear();
40→  const month = date.toLocaleDateString('en-US', { month: 'short' });
41→  const day = date.getDate();
42→
43→  if (sameYear) {
44→    return `${month} ${day}`;
45→  }
46→
47→  return `${month} ${day}, ${date.getFullYear()}`;
48→}
