  1→import type { ReactNode } from 'react';
  2→import { useCallback } from 'react';
  3→import { TAG_COLOR_HEX } from '../../../constants/tag_colors';
  4→import type { ListItemAccessoryData } from '../../../types';
  5→import { formatRelativeDate } from '../../../utils/format_date';
  6→import { useListContext } from '../list_context';
  7→import './list_item.scss';
  8→
  9→export interface ListItemProps {
 10→  index: number;
 11→  icon?: ReactNode;
 12→  title: string;
 13→  subtitle?: string;
 14→  accessories?: ListItemAccessoryData[];
 15→  onClick?: () => void;
 16→}
 17→
 18→export function ListItem({
 19→  index,
 20→  icon,
 21→  title,
 22→  subtitle,
 23→  accessories,
 24→  onClick,
 25→}: ListItemProps) {
 26→  const { activeIndex, setActiveIndex } = useListContext();
 27→  const isActive = activeIndex === index;
 28→
 29→  const handleMouseEnter = useCallback(() => {
 30→    setActiveIndex(index);
 31→  }, [
 32→    index,
 33→    setActiveIndex,
 34→  ]);
 35→
 36→  return (
 37→    <div
 38→      id={`list-item-${index}`}
 39→      className={`list-item${isActive ? ' list-item--active' : ''}`}
 40→      data-list-index={index}
 41→      role="option"
 42→      aria-selected={isActive}
 43→      onMouseEnter={handleMouseEnter}
 44→      onClick={onClick}
 45→    >
 46→      <div className="list-item__left">
 47→        {icon && <span className="list-item__icon">{icon}</span>}
 48→        <span className="list-item__title">{title}</span>
 49→        {subtitle && <span className="list-item__subtitle">{subtitle}</span>}
 50→      </div>
 51→      {accessories && accessories.length > 0 && (
 52→        <div className="list-item__accessories">
 53→          {accessories.map((accessory, i) => {
 54→            if (accessory.tag) {
 55→              const hex = accessory.tag.color
 56→                ? TAG_COLOR_HEX[accessory.tag.color]
 57→                : undefined;
 58→              return (
 59→                <span
 60→                  key={i}
 61→                  className="list-item__accessory-tag"
 62→                  style={
 63→                    hex
 64→                      ? {
 65→                          color: hex,
 66→                          backgroundColor: `${hex}26`,
 67→                        }
 68→                      : undefined
 69→                  }
 70→                >
 71→                  {accessory.tag.text}
 72→                </span>
 73→              );
 74→            }
 75→            const displayText = accessory.date
 76→              ? formatRelativeDate(accessory.date)
 77→              : accessory.text;
 78→
 79→            return (
 80→              <span
 81→                key={i}
 82→                className="list-item__accessory"
 83→                title={
 84→                  accessory.date ? accessory.date.toLocaleString() : undefined
 85→                }
 86→              >
 87→                {accessory.icon}
 88→                {displayText && (
 89→                  <span className="list-item__accessory-text">
 90→                    {displayText}
 91→                  </span>
 92→                )}
 93→              </span>
 94→            );
 95→          })}
 96→        </div>
 97→      )}
 98→    </div>
 99→  );
100→}
